function.arguments:
{"command": "curl -s "https://api.telegram.org/bot$(grep -A5 'telegram:' ~/.hermes/config.yaml | grep 'api_key' | head -1 | awk '{print $2}')/getUpdates" | python3 -c "
import json, sys
data = json.load(sys.stdin)
if data.get('ok'):
    for update in data['result'][-5:]:
        msg = update.get('message', {})
        chat = msg.get('chat', {})
        print(f'Chat ID: {chat.get(\"id\")} | Title: {chat.get(\"title\", \"N/A\")} | Type: {chat.get(\"type\")}')
        if chat.get('type') == 'private':
            print(f'  Username: @{chat.get(\"username\", \"N/A\")}')
        else:
            print(f'  Group Title: {chat.get(\"title\")}')
"
", "timeout": 15}
